export type Json =
  | null
  | boolean
  | number
  | string
  | Json[]
  | { [key: string]: Json };

export function parse(s: string): Json {
  const source = s;
  let index = 0;

  const peek = (): string => source[index] ?? '';
  const next = (): string => source[index++];
  const eatWhitespace = (): void => {
    while (true) {
      const ch = peek();
      if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
        next();
      } else {
        break;
      }
    }
  };

  const unexpected = (): never => {
    throw new Error(`Unexpected character at position ${index}: '${peek()}'`);
  };

  const expect = (ch: string): void => {
    if (peek() !== ch) {
      unexpected();
    }
    next();
  };

  const parseValue = (): Json => {
    eatWhitespace();
    const ch = peek();
    switch (ch) {
      case '{':
        return parseObject();
      case '[':
        return parseArray();
      case '"':
        return parseString();
      case 't':
      case 'f':
      case 'n':
        return parseLiteral();
      default:
        if (ch === '-' || (ch >= '0' && ch <= '9')) {
          return parseNumber();
        }
        unexpected();
    }
  };

  const parseObject = (): Json => {
    expect('{');
    eatWhitespace();
    if (peek() === '}') {
      next();
      return {};
    }
    const obj: { [key: string]: Json } = {};
    while (true) {
      eatWhitespace();
      const key = parseString();
      if (typeof key !== 'string') {
        throw new Error('Object key must be a string');
      }
      eatWhitespace();
      expect(':');
      eatWhitespace();
      const value = parseValue();
      obj[key] = value;
      eatWhitespace();
      const after = peek();
      if (after === ',') {
        next(); // consume comma
        eatWhitespace();
        if (peek() === '}') {
          throw new Error('Trailing comma in object');
        }
        continue;
      }
      if (after === '}') {
        next();
        break;
      }
      unexpected();
    }
    return obj;
  };

  const parseArray = (): Json => {
    expect('[');
    eatWhitespace();
    if (peek() === ']') {
      next();
      return [];
    }
    const arr: Json[] = [];
    while (true) {
      eatWhitespace();
      const value = parseValue();
      arr.push(value);
      eatWhitespace();
      const after = peek();
      if (after === ',') {
        next(); // consume comma
        eatWhitespace();
        if (peek() === ']') {
          throw new Error('Trailing comma in array');
        }
        continue;
      }
      if (after === ']') {
        next();
        break;
      }
      unexpected();
    }
    return arr;
  };

  const parseString = (): string => {
    expect('"');
    let result = '';
    while (true) {
      const ch = peek();
      if (ch === '') {
        throw new Error('Unterminated string');
      }
      if (ch === '"') {
        next();
        break;
      }
      if (ch === '\\') {
        next(); // consume backslash
        const esc = peek();
        if (esc === '') {
          throw new Error('Unterminated escape in string');
        }
        next(); // consume escape char
        switch (esc) {
          case '"':
            result += '"';
            break;
          case '\\':
            result += '\\';
            break;
          case '/':
            result += '/';
            break:
          case 'b':
            result += '\b';
            break;
          case 'f':
            result += '\f';
            break;
          case 'n':
            result += '\n';
            break;
          case 'r':
            result += '\r';
            break;
          case 't':
            result += '\t';
            break;
          case 'u':
            const hex = source.substr(index, 4);
            if (!/^[0-9a-fA-F]{4}$/.test(hex)) {
              throw new Error('Invalid Unicode escape');
            }
            index += 4;
            result += String.fromCharCode(parseInt(hex, 16));

