type ParseQuery<S extends string> = S extends '' 
  ? {} 
  : S extends `${infer First}&${infer Rest}` 
    ? Merge<ParsePair<First>, ParseQuery<Rest>> 
    : ParsePair<S>;

type ParsePair<P extends string> = P extends `${infer K}=${infer V}` 
  ? { [kk in K]: V } 
  : {};

type Merge<A, B> = A & B;

export type { ParseQuery };

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private handlers: {
    [K in keyof TEvents]?: Array<(...args: TEvents[K]) => void>;
  } = {};

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const list = this.handlers[name] ?? (this.handlers[name] = [] as Array<(...args: TEvents[K]) => void>);
    list.push(handler);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const listeners = this.handlers[name];
    if (listeners) {
      for (const handler of listeners) {
        handler(...args);
      }
    }
  }
}

class MaxHeap {
    private data: number[] = [];
    private size(): number { return this.data.length; }
    private compare(i: number, j: number): boolean { return this.data[i] > this.data[j]; }
    private swap(i: number, j: number): void {
        [this.data[i], this.data[j]] = [this.data[j], this.data[i]];
    }
    push(val: number): void {
        this.data.push(val);
        let i = this.data.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (!this.compare(i, p)) break;
            this.swap(i, p);
            i = p;
        }
    }
    pop(): number {
        if (this.data.length === 0) throw new Error("Heap empty");
        const top = this.data[0];
        const last = this.data.pop()!;
        if (this.data.length > 0) {
            this.data[0] = last;
            let i = 0;
            while (true) {
                const left = 2 * i + 1;
                const right = left + 1;
                let largest = i;
                if (left < this.data.length && this.compare(left, largest)) largest = left;
                if (right < this.data.length && this.compare(right, largest)) largest = right;
                if (largest === i) break;
                this.swap(i, largest);
                i = largest;
            }
        }
        return top;
    }
    peek(): number {
        if (this.data.length === 0) throw new Error("Heap empty");
        return this.data[0];
    }
}

class MinHeap {
    private data: number[] = [];
    private size(): number { return this.data.length; }
    private compare(i: number, j: number): boolean { return this.data[i] < this.data[j]; }
    private swap(i: number, j: number): void {
        [this.data[i], this.data[j]] = [this.data[j], this.data[i]];
    }
    push(val: number): void {
        this.data.push(val);
        let i = this.data.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (!this.compare(i, p)) break;
            this.swap(i, p);
            i = p;
        }
    }
    pop(): number {
        if (this.data.length === 0) throw new Error("Heap empty");
        const top = this.data[0];
        const last = this.data.pop()!;
        if (this.data.length > 0) {
            this.data[0] = last;
            let i = 0;
            while (true) {
                const left = 2 * i + 1;
                const right = left + 1;
                let smallest = i;
                if (left < this.data.length && this.compare(left, smallest)) smallest = left;
                if (right < this.data.length && this.compare(right, smallest)) smallest = right;
                if (smallest === i) break;
                this.swap(i, smallest);
                i = smallest;
            }
        }
        return top;
    }
    peek(): number {
        if (this.data.length === 0) throw new Error("Heap empty");
        return this.data[0];
    }
}

export class MedianStream {
    private low: MaxHeap = new MaxHeap();  // max-heap for the lower half
    private high: MinHeap = new MinHeap(); // min-heap for the upper half

    add(n: number): void {
        if (this.low.size() === 0 || n <= this.low.peek()) {
            this.low.push(n);
        } else {
            this.high.push(n);
        }
        this.rebalance();
    }

    median(): number {
        if (this.low.size() === 0 && this.high.size() === 0) {
            throw new Error("No elements added yet");
        }
        if (this.low.size() === this.high.size()) {
            return (this.low.peek() + this.high.peek()) / 2;
        }
        return this.low.size() > this.high.size() ? this.low.peek() : this.high.peek();
    }

    private rebalance(): void {
        const lowSize = this.low.size();
        const highSize = this.high.size();
        if (lowSize > highSize + 1) {
            this.high.push(this.low.pop());
        } else if (highSize > lowSize + 1) {
            this.low.push(this.high.pop());
        }
    }
}
